const ethers = require('ethers');

class SecureDApp {
    constructor() {
        this.provider = null;
        this.signer = null;
        this.allowedContracts = new Map();
        this.maxGasLimit = ethers.BigNumber.from('500000');
        this.maxGasPrice = ethers.utils.parseUnits('100', 'gwei');
    }

    async initialize() {
        if (typeof window.ethereum === 'undefined') {
            throw new Error('MetaMask or compatible wallet not found');
        }
        
        this.provider = new ethers.providers.Web3Provider(window.ethereum);
        await this.provider.send('eth_requestAccounts', []);
        this.signer = this.provider.getSigner();
    }

    registerContract(contractAddress, abi, allowedFunctions) {
        if (!ethers.utils.isAddress(contractAddress)) {
            throw new Error('Invalid contract address');
        }

        const normalizedAddress = ethers.utils.getAddress(contractAddress);
        
        this.allowedContracts.set(normalizedAddress, {
            abi: abi,
            allowedFunctions: new Set(allowedFunctions)
        });
    }

    validateAddress(address) {
        if (!address || typeof address !== 'string') {
            throw new Error('Invalid address format');
        }
        
        if (!ethers.utils.isAddress(address)) {
            throw new Error('Invalid Ethereum address');
        }
        
        return ethers.utils.getAddress(address);
    }

    validateAmount(amount) {
        if (!amount || typeof amount !== 'string') {
            throw new Error('Invalid amount format');
        }

        const sanitizedAmount = amount.trim();
        
        if (!/^\d+(\.\d+)?$/.test(sanitizedAmount)) {
            throw new Error('Amount must be a valid number');
        }

        const parsedAmount = ethers.utils.parseEther(sanitizedAmount);
        
        if (parsedAmount.lte(0)) {
            throw new Error('Amount must be greater than 0');
        }

        if (parsedAmount.gt(ethers.utils.parseEther('1000000'))) {
            throw new Error('Amount exceeds maximum allowed');
        }

        return parsedAmount;
    }

    validateFunctionName(functionName) {
        if (!functionName || typeof functionName !== 'string') {
            throw new Error('Invalid function name');
        }

        const sanitized = functionName.trim();
        
        if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(sanitized)) {
            throw new Error('Function name contains invalid characters');
        }

        return sanitized;
    }

    validateGasLimit(gasLimit) {
        if (!gasLimit) {
            return this.maxGasLimit;
        }

        const gas = ethers.BigNumber.from(gasLimit);
        
        if (gas.lte(0) || gas.gt(this.maxGasLimit)) {
            throw new Error('Gas limit out of acceptable range');
        }

        return gas;
    }

    validateGasPrice(gasPrice) {
        if (!gasPrice) {
            return null;
        }

        const price = ethers.BigNumber.from(gasPrice);
        
        if (price.lte(0) || price.gt(this.maxGasPrice)) {
            throw new Error('Gas price out of acceptable range');
        }

        return price;
    }

    sanitizeParameters(params) {
        if (!Array.isArray(params)) {
            throw new Error('Parameters must be an array');
        }

        return params.map(param => {
            if (typeof param === 'string') {
                if (param.startsWith('0x')) {
                    return param;
                }
                return param.trim();
            }
            if (typeof param === 'number' || typeof param === 'boolean') {
                return param;
            }
            if (ethers.BigNumber.isBigNumber(param)) {
                return param;
            }
            throw new Error('Invalid parameter type');
        });
    }

    async callContractFunction(contractAddress, functionName, parameters, options = {}) {
        const validatedAddress = this.validateAddress(contractAddress);
        const validatedFunction = this.validateFunctionName(functionName);
        
        const contractConfig = this.allowedContracts.get(validatedAddress);
        if (!contractConfig) {
            throw new Error('Contract not registered in allowlist');
        }

        if (!contractConfig.allowedFunctions.has(validatedFunction)) {
            throw new Error('Function not allowed for this contract');
        }

        const sanitizedParams = this.sanitizeParameters(parameters);
        
        const contract = new ethers.Contract(
            validatedAddress,
            contractConfig.abi,
            this.signer
        );

        if (typeof contract[validatedFunction] !== 'function') {
            throw new Error('Function does not exist in contract ABI');
        }

        const txOptions = {};
        
        if (options.gasLimit) {
            txOptions.gasLimit = this.validateGasLimit(options.gasLimit);
        }
        
        if (options.gasPrice) {
            txOptions.gasPrice = this.validateGasPrice(options.gasPrice);
        }

        if (options.value) {
            txOptions.value = this.validateAmount(options.value);
        }

        const userAddress = await this.signer.getAddress();
        const balance = await this.provider.getBalance(userAddress);
        
        if (txOptions.value && balance.lt(txOptions.value)) {
            throw new Error('Insufficient balance for transaction');
        }

        const tx = await contract[validatedFunction](...sanitizedParams, txOptions);
        
        return {
            hash: tx.hash,
            from: tx.from,
            to: tx.to,
            value: tx.value ? ethers.utils.formatEther(tx.value) : '0',
            gasLimit: tx.gasLimit.toString(),
            nonce: tx.nonce
        };
    }

    async waitForTransaction(txHash) {
        if (!txHash || typeof txHash !== 'string' || !txHash.match(/^0x[a-fA-F0-9]{64}$/)) {
            throw new Error('Invalid transaction hash');
        }

        const receipt = await this.provider.waitForTransaction(txHash);
        
        return {
            transactionHash: receipt.transactionHash,
            blockNumber: receipt.blockNumber,
            gasUsed: receipt.gasUsed.toString(),
            status: receipt.status,
            confirmations: receipt.confirmations
        };
    }

    async readContractData(contractAddress, functionName, parameters = []) {
        const validatedAddress = this.validateAddress(contractAddress);
        const validatedFunction = this.validateFunctionName(functionName);
        
        const contractConfig = this.allowedContracts.get(validatedAddress);
        if (!contractConfig) {
            throw new Error('Contract not registered in allowlist');
        }

        const sanitizedParams = this.sanitizeParameters(parameters);
        
        const contract = new ethers.Contract(
            validatedAddress,
            contractConfig.abi,
            this.provider
        );

        if (typeof contract[validatedFunction] !== 'function') {
            throw new Error('Function does not exist in contract ABI');
        }

        const result = await contract[validatedFunction](...sanitizedParams);
        
        return result;
    }

    async estimateGas(contractAddress, functionName, parameters, options = {}) {
        const validatedAddress = this.validateAddress(contractAddress);
        const validatedFunction = this.validateFunctionName(functionName);
        
        const contractConfig = this.allowedContracts.get(validatedAddress);
        if (!contractConfig) {
            throw new Error('Contract not registered in allowlist');
        }

        const sanitizedParams = this.sanitizeParameters(parameters);
        
        const contract = new ethers.Contract(
            validatedAddress,
            contractConfig.abi,
            this.signer
        );

        const txOptions = {};
        if (options.value) {
            txOptions.value = this.validateAmount(options.value);
        }

        const gasEstimate = await contract.estimateGas[validatedFunction](
            ...sanitizedParams,
            txOptions
        );

        return gasEstimate.toString();
    }

    async getCurrentGasPrice() {
        const gasPrice = await this.provider.getGasPrice();
        return {
            wei: gasPrice.toString(),
            gwei: ethers.utils.formatUnits(gasPrice, 'gwei')
        };
    }

    async getAccountBalance(address) {
        const validatedAddress = this.validateAddress(address);
        const balance = await this.provider.getBalance(validatedAddress);
        
        return {
            wei: balance.toString(),
            ether: ethers.utils.formatEther(balance)
        };
    }

    async getNetworkInfo() {
        const network = await this.provider.getNetwork();
        const blockNumber = await this.provider.getBlockNumber();
        
        return {
            chainId: network.chainId,
            name: network.name,
            blockNumber: blockNumber
        };
    }
}

